mapper.select:
SELECT TO_CHAR(a.attend_date, 'YYYY-MM-DD') AS date, COUNT(*) AS total, COUNT(CASE WHEN a.status = 'PRESENT' THEN 1 END) AS present, COUNT(CASE WHEN a.status = 'ABSENT' THEN 1 END) AS absent, CASE WHEN COUNT(*) = 0 THEN 0 ELSE ROUND(COUNT(CASE WHEN a.status = 'PRESENT' THEN 1 END) * 100.0 / COUNT(*), 2) END AS rate FROM erp_attendance a
TO_CHAR(a.attend_date, 'YYYY') = #{year}
AND TO_CHAR(a.attend_date, 'MM') = #{month}
GROUP BY a.attend_date ORDER BY a.attend_date DESC
